import{_ as r,o as d,c as o,ag as n}from"./chunks/framework.C9sp7nFj.js";const c=JSON.parse('{"title":"西湖攻略2026 | iVoyageWiki","description":"杭州西湖详细游玩攻略，含门票交通路线拍照机位全指南","frontmatter":{"title":"西湖攻略2026 | iVoyageWiki","description":"杭州西湖详细游玩攻略，含门票交通路线拍照机位全指南"},"headers":[],"relativePath":"destinations/中国/杭州/西湖.md","filePath":"destinations/中国/杭州/西湖.md","lastUpdated":null}'),s={name:"destinations/中国/杭州/西湖.md"};function a(i,t,e,l,g,h){return d(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="🌊-西湖" tabindex="-1">🌊 西湖 <a class="header-anchor" href="#🌊-西湖" aria-label="Permalink to &quot;🌊 西湖&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1574572590303-18ed35d0ecac?w=800&amp;h=400&amp;fit=crop" alt="西湖全景"></p><blockquote><p><strong>【一句话定位】</strong> 西湖是中国唯一的世界文化遗产湖泊类景观，适合所有类型的旅行者——亲子漫步、情侣约会、摄影创作、文化探访、休闲放松，每个人都能在这里找到属于自己的乐趣。</p></blockquote><h2 id="【基础信息】" tabindex="-1">【基础信息】 <a class="header-anchor" href="#【基础信息】" aria-label="Permalink to &quot;【基础信息】&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>🎫 <strong>门票价格</strong></td><td>西湖景区<strong>免费开放</strong>（环湖区域全部免费）<br>• 部分收费景点：雷峰塔¥40、三潭印月登岛¥55（含游船）、岳王庙¥25、净慈寺¥10<br>• 学生/老人票：各收费景点均有半价优惠（需持证）</td></tr><tr><td>⏰ <strong>开放时间</strong></td><td>西湖环湖区域 <strong>全天24小时开放</strong><br>• 收费景点通常 8:00-17:00（夏季延长至17:30）<br>• 雷峰塔 8:00-20:30（夜景绝佳）</td></tr><tr><td>📍 <strong>地址</strong></td><td>浙江省杭州市西湖区，龙井路1号（西湖风景名胜区管委会）</td></tr><tr><td>🚇 <strong>交通</strong></td><td>地铁1号线 <strong>龙翔桥站</strong>（C口出，步行3分钟到湖滨）<br>• 地铁1号线 <strong>定安路站</strong>（步行8分钟到西湖）<br>• 公交：4路、7路、27路、51路等可达</td></tr><tr><td>⏱️ <strong>建议游览时长</strong></td><td>环湖徒步约4-5小时；精华游2-3小时；骑行约2小时</td></tr><tr><td>📱 <strong>预约方式</strong></td><td>环湖免费区域无需预约<br>• 雷峰塔/岳王庙等收费景点：微信公众号&quot;杭州西湖风景名胜区&quot;提前1天预约</td></tr><tr><td>👥 <strong>适合人群</strong></td><td>亲子⭐⭐⭐⭐⭐ / 老人⭐⭐⭐⭐⭐ / 情侣⭐⭐⭐⭐⭐ / 摄影⭐⭐⭐⭐⭐</td></tr></tbody></table><h2 id="【核心亮点】" tabindex="-1">【核心亮点】 <a class="header-anchor" href="#【核心亮点】" aria-label="Permalink to &quot;【核心亮点】&quot;">​</a></h2><ul><li>★★★★★ <strong>苏堤春晓</strong>——春天苏堤全长2.8公里，桃花垂柳交相辉映，是西湖十景之首</li><li>★★★★★ <strong>三潭印月</strong>——西湖标志性景观，1元人民币背面图案原型，登岛观景最佳</li><li>★★★★★ <strong>雷峰夕照</strong>——傍晚登雷峰塔，俯瞰西湖全景+日落，金色湖面如梦如幻</li><li>★★★★☆ <strong>断桥残雪</strong>——许仙白娘子相会之地，雪景最出名，平日也可远眺保俶塔</li><li>★★★★☆ <strong>音乐喷泉</strong>——每晚19:00/20:00两场，喷泉+灯光+音乐，免费观赏</li></ul><h2 id="【最佳游览时间】" tabindex="-1">【最佳游览时间】 <a class="header-anchor" href="#【最佳游览时间】" aria-label="Permalink to &quot;【最佳游览时间】&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时段</th><th>体验</th></tr></thead><tbody><tr><td>🌅 <strong>上午 6:00-8:00</strong></td><td>晨雾弥漫，湖面如镜，几乎无游客，最适合拍倒影和晨景</td></tr><tr><td>☀️ <strong>上午 9:00-11:00</strong></td><td>光线柔和，适合白堤/苏堤散步+坐游船，游客开始增多</td></tr><tr><td>🌇 <strong>下午 16:00-18:00</strong></td><td><strong>最佳时段！</strong> 日落+晚霞染红湖面，雷峰塔方向金光万丈</td></tr><tr><td>🌙 <strong>晚上 19:00-21:00</strong></td><td>湖滨灯光亮起，音乐喷泉+夜游西湖，浪漫气氛拉满</td></tr></tbody></table><p><strong>⚠️ 避开时间：</strong> 五一/十一假期人山人海；周末下午湖滨人流极大；暑期白天高温暴晒</p><h2 id="【推荐游览路线】" tabindex="-1">【推荐游览路线】 <a class="header-anchor" href="#【推荐游览路线】" aria-label="Permalink to &quot;【推荐游览路线】&quot;">​</a></h2><p><strong>经典半日游（3-4小时）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>断桥 → 白堤 → 平湖秋月 → 苏堤 → 花港观鱼 → 雷峰塔 → 音乐喷泉</span></span></code></pre></div><ul><li><strong>断桥（20min）</strong>：西湖标志性起点，远眺保俶塔最佳位置</li><li><strong>白堤（30min）</strong>：1公里长的湖中堤，两侧垂柳依依</li><li><strong>平湖秋月（15min）</strong>：喝茶赏湖景，秋天看月亮倒映最佳</li><li><strong>苏堤（40min）</strong>：2.8公里长堤，六桥起伏，春天桃花绝美</li><li><strong>花港观鱼（30min）</strong>：红鲤鱼成群，可买饲料喂鱼，小朋友最爱</li><li><strong>雷峰塔（1h）</strong>：登塔俯瞰西湖全景，看&quot;雷峰夕照&quot;</li><li><strong>音乐喷泉（30min）</strong>：湖滨路看免费喷泉表演</li></ul><p><strong>一日深度游（6-7小时）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>断桥 → 白堤 → 孤山（省博） → 苏堤 → 花港观鱼 → 乘船至三潭印月 → 岳王庙 → 雷峰塔 → 音乐喷泉</span></span></code></pre></div><h2 id="【必打卡拍照机位】" tabindex="-1">【必打卡拍照机位】 <a class="header-anchor" href="#【必打卡拍照机位】" aria-label="Permalink to &quot;【必打卡拍照机位】&quot;">​</a></h2><table tabindex="0"><thead><tr><th>机位</th><th>拍什么</th><th>怎么拍</th></tr></thead><tbody><tr><td>📸 断桥东侧桥头</td><td>断桥+保俶塔同框</td><td>日出时分，低角度拍桥弧线，远处塔影</td></tr><tr><td>📸 白堤中段长椅</td><td>白堤延伸线+孤山背景</td><td>坐在长椅上拍背影，两侧垂柳做前景框</td></tr><tr><td>📸 苏堤压堤桥</td><td>苏堤纵深感+远山层叠</td><td>站在桥顶，用长焦压缩空间感</td></tr><tr><td>📸 三潭印月岛北侧</td><td>三座石塔+雷峰塔同框</td><td>下午4-5点，逆光拍三塔剪影</td></tr><tr><td>📸 雷峰塔五层观景台</td><td>西湖全景俯瞰</td><td>傍晚日落前1小时，金色光线打满画面</td></tr><tr><td>📸 长桥公园</td><td>雷峰塔+湖面倒影</td><td>雨后地面有积水时，拍镜面对称</td></tr><tr><td>📸 湖滨路音乐喷泉前</td><td>喷泉+城市天际线</td><td>夜晚用慢门拍摄，灯光拖尾效果</td></tr></tbody></table><h2 id="【隐藏玩法-小众体验】" tabindex="-1">【隐藏玩法/小众体验】 <a class="header-anchor" href="#【隐藏玩法-小众体验】" aria-label="Permalink to &quot;【隐藏玩法/小众体验】&quot;">​</a></h2><ul><li>🚲 <strong>清晨骑行西湖</strong>：早6点前共享单车环湖，全程约10公里，1小时骑完，没有人的西湖完全是另一番景象</li><li>🛶 <strong>手划船环湖</strong>：在苏堤南口找手划船师傅（约¥150/小时），走内西湖水道，不坐机动船，安静穿过桥洞</li><li>🍵 <strong>龙井村喝一杯</strong>：从苏堤南口步行20分钟到龙井村，找农家喝杯明前龙井（¥30/杯），看茶农炒茶</li><li>📖 <strong>孤山脚下西泠印社</strong>：中国最著名的篆刻社团，藏在孤山深处，庭院精致，几乎没人</li><li>🌸 <strong>乌龟潭小众赏花</strong>：杨公堤附近的乌龟潭，樱花/梨花季人少花美，本地人才知道</li></ul><h2 id="【周边美食推荐】" tabindex="-1">【周边美食推荐】 <a class="header-anchor" href="#【周边美食推荐】" aria-label="Permalink to &quot;【周边美食推荐】&quot;">​</a></h2><table tabindex="0"><thead><tr><th>餐厅</th><th>人均</th><th>必点菜品</th><th>距西湖</th></tr></thead><tbody><tr><td>🏆 <strong>楼外楼（孤山店）</strong></td><td>¥180</td><td>西湖醋鱼、东坡肉、龙井虾仁</td><td>白堤尽头步行3分钟</td></tr><tr><td>🥟 <strong>知味观（湖滨总店）</strong></td><td>¥80</td><td>片儿川、猫耳朵、小笼包</td><td>湖滨路步行5分钟</td></tr><tr><td>🍜 <strong>奎元馆</strong></td><td>¥50</td><td>虾爆鳝面、片儿川</td><td>解放路步行8分钟</td></tr><tr><td>🫓 <strong>葱包烩摊（吴山夜市）</strong></td><td>¥10</td><td>葱包烩、定胜糕</td><td>湖滨南步行10分钟</td></tr><tr><td>🍵 <strong>湖畔居茶楼</strong></td><td>¥120（含茶点）</td><td>龙井茶+茶点套餐</td><td>湖滨路湖边</td></tr></tbody></table><h2 id="【避坑提示】" tabindex="-1">【避坑提示】 <a class="header-anchor" href="#【避坑提示】" aria-label="Permalink to &quot;【避坑提示】&quot;">​</a></h2><ul><li>❌ <strong>不要在湖边买茶叶</strong>——路边的&quot;龙井茶&quot;大部分是外地茶冒充，去龙井村或正规茶庄买</li><li>❌ <strong>不要坐湖边揽客的游船</strong>——私人游船价格虚高（开口¥100+），去码头坐官方游船¥55含三潭印月门票</li><li>❌ <strong>节假日别打车上苏堤</strong>——苏堤周末禁止机动车通行，且周边堵车严重，地铁龙翔桥站最靠谱</li><li>❌ <strong>雷峰塔不用坐电梯</strong>——排队半小时，走楼梯只需5分钟，还能看每层不同展览</li><li>✅ <strong>带空水瓶</strong>——西湖边有直饮水点（白堤/苏堤/湖滨），免费接水省钱又环保</li><li>✅ <strong>下雨天也别取消行程</strong>——&quot;烟雨西湖&quot;才是真正的江南韵味，反而雨天人少更有意境</li></ul>',24)])])}const p=r(s,[["render",a]]);export{c as __pageData,p as default};
